import java.util.Scanner;
import java.text.DecimalFormat;

public class MortgageCalculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        boolean continueCalculating = true;

        while (continueCalculating) {
            try {
                System.out.print("Enter principal loan amount (or -1 to exit): ");
                float principal = scanner.nextFloat();

                if (principal == -1) {
                    continueCalculating = false;
                    continue;
                }

                if (principal <= 0) {
                    System.out.println("Error: Principal must be a positive number");
                    continue;
                }

                System.out.print("Enter annual interest rate (as a percentage): ");
                float annualInterestRate = scanner.nextFloat();

                if (annualInterestRate <= 0) {
                    System.out.println("Error: Interest rate must be a positive number");
                    continue;
                }

                System.out.print("Enter loan period in years: ");
                int years = scanner.nextInt();

                if (years <= 0) {
                    System.out.println("Error: Loan period must be a positive integer");
                    continue;
                }

                double monthlyPayment = calculateMortgage(principal, annualInterestRate, years);
                DecimalFormat df = new DecimalFormat("#.##");
                System.out.println("Monthly mortgage payment: $" + df.format(monthlyPayment));

            } catch (Exception e) {
                System.out.println("Invalid input. Please try again.");
                scanner.nextLine(); // Clear the scanner buffer
            }

            System.out.println();
        }

        System.out.println("Thank you for using the Mortgage Calculator!");
        scanner.close();
    }

    public static double calculateMortgage(float principal, float annualInterestRate, int years) {
        if (principal <= 0 || annualInterestRate <= 0 || years <= 0) {
            throw new IllegalArgumentException("All inputs must be positive numbers");
        }

        float monthlyInterestRate = annualInterestRate / 100 / 12;
        int numberOfPayments = years * 12;

        double monthlyPayment = principal * 
                (monthlyInterestRate * Math.pow(1 + monthlyInterestRate, numberOfPayments)) / 
                (Math.pow(1 + monthlyInterestRate, numberOfPayments) - 1);

        return monthlyPayment;
    }
}

fn paginate_results(page_number: i32, page_size: i32) -> Result<Vec<String>, String> {
    // Validate pagination parameters
    if page_number <= 0 {
        return Err("Error: Page number must be positive".to_string());
    }
    if page_size <= 0 {
        return Err("Error: Page size must be positive".to_string());
    }

    // Simulate database with sample data
    let data: Vec<String> = (1..=100)
        .map(|i| format!("Item {}", i))
        .collect();

    // Calculate start and end indices for pagination
    let start_index = (page_number - 1) as usize * page_size as usize;
    let end_index = start_index + page_size as usize;

    // Check if start index is out of bounds
    if start_index >= data.len() {
        return Err("Error: Page number exceeds available data".to_string());
    }

    // Get the paginated subset of data
    let paginated_data: Vec<String> = data
        .iter()
        .skip(start_index)
        .take(page_size as usize)
        .cloned()
        .collect();

    Ok(paginated_data)
}

