bool saveFilesToDirectory(const std::vector<std::string>& filenames, const std::string& directoryPath) {
    namespace fs = std::filesystem;

    // Check if directory exists and is writable
    if (!fs::exists(directoryPath)) {
        std::cerr << "Error: Directory " << directoryPath << " does not exist." << std::endl;
        return false;
    }

    // Check if directory is writable by creating a test file
    std::string testFilePath = fs::path(directoryPath) / "write_test_temp.txt";
    try {
        std::ofstream testFile(testFilePath);
        if (!testFile) {
            std::cerr << "Error: Directory " << directoryPath << " is not writable." << std::endl;
            return false;
        }
        testFile.close();
        fs::remove(testFilePath);
    } catch (const std::exception& e) {
        std::cerr << "Error: Directory " << directoryPath << " is not writable: " << e.what() << std::endl;
        return false;
    }

    bool allSuccessful = true;

    // Process each file
    for (const auto& filename : filenames) {
        fs::path sourcePath = filename;
        fs::path destPath = fs::path(directoryPath) / sourcePath.filename();

        // Check if source file exists
        if (!fs::exists(sourcePath)) {
            std::cerr << "Error: File " << filename << " does not exist." << std::endl;
            allSuccessful = false;
            continue;
        }

        // Try to move the file
        std::error_code ec;
        fs::rename(sourcePath, destPath, ec);

        if (ec) {
            std::cerr << "Error moving file " << filename << " to " << directoryPath 
                      << ": " << ec.message() << std::endl;
            allSuccessful = false;
        } else {
            std::cout << "Successfully moved " << filename << " to " << directoryPath << std::endl;
        }
    }

    return allSuccessful;
}

