public Configuration loadConfiguration(String xmlFilePath) throws ConfigurationException {
    Configuration config = new Configuration();

    try {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new File(xmlFilePath));
        document.getDocumentElement().normalize();

        NodeList portNodes = document.getElementsByTagName("port");
        if (portNodes.getLength() == 0) {
            throw new ConfigurationException("Missing required 'port' tag in configuration file");
        }
        try {
            int port = Integer.parseInt(portNodes.item(0).getTextContent());
            config.setPort(port);
        } catch (NumberFormatException e) {
            throw new ConfigurationException("Invalid port number format in configuration file");
        }

        NodeList timeoutNodes = document.getElementsByTagName("timeout");
        if (timeoutNodes.getLength() == 0) {
            throw new ConfigurationException("Missing required 'timeout' tag in configuration file");
        }
        try {
            int timeout = Integer.parseInt(timeoutNodes.item(0).getTextContent());
            config.setTimeout(timeout);
        } catch (NumberFormatException e) {
            throw new ConfigurationException("Invalid timeout format in configuration file");
        }

        NodeList serverAddressNodes = document.getElementsByTagName("serverAddress");
        if (serverAddressNodes.getLength() == 0) {
            throw new ConfigurationException("Missing required 'serverAddress' tag in configuration file");
        }
        config.setServerAddress(serverAddressNodes.item(0).getTextContent());

    } catch (FileNotFoundException e) {
        throw new ConfigurationException("Configuration file not found: " + xmlFilePath, e);
    } catch (IOException e) {
        throw new ConfigurationException("Error reading configuration file: " + e.getMessage(), e);
    } catch (ParserConfigurationException | SAXException e) {
        throw new ConfigurationException("Error parsing XML configuration file: " + e.getMessage(), e);
    }

    return config;
}

public class ConfigurationException extends Exception {
    public ConfigurationException(String message) {
        super(message);
    }

    public ConfigurationException(String message, Throwable cause) {
        super(message, cause);
    }
}

bool toggleFeature(bool activate) {
