    std::string action = activate ? "activate" : "deactivate";
    std::string confirmation;

    std::cout << "Do you want to " << action << " this feature? (y/n): ";
    std::cin >> confirmation;

    if (confirmation == "y" || confirmation == "Y") {
        featureEnabled = activate;
        std::cout << "Feature successfully " << (activate ? "activated" : "deactivated") << "." << std::endl;
        return true;
    } else if (confirmation == "n" || confirmation == "N") {
        std::cout << "Operation canceled. Feature remains " << (featureEnabled ? "activated" : "deactivated") << "." << std::endl;
        return false;
    } else {
        std::cout << "Error: Invalid input. Operation canceled." << std::endl;
        return false;
    }
}

void configureFeatures(std::set<std::string>& enabledFeatures, json& featureConfigs) {
    bool exitMenu = false;
    while (!exitMenu) {
        std::cout << "\n===== Feature Configuration Menu =====\n";
        std::cout << "1. View current configuration\n";
        std::cout << "2. Enable a feature\n";
        std::cout << "3. Disable a feature\n";
        std::cout << "4. Update feature parameters\n";
        std::cout << "5. Save configuration to file\n";
        std::cout << "6. Load configuration from file\n";
        std::cout << "7. Reset to default settings\n";
        std::cout << "8. Exit\n";
        std::cout << "Enter your choice: ";

        int choice;
        std::cin >> choice;
        std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');

        switch (choice) {
            case 1: {  // View current configuration
                std::cout << "\nCurrent Configuration:\n";
                std::cout << "Enabled Features: ";
                if (enabledFeatures.empty()) {
                    std::cout << "None\n";
                } else {
                    for (const auto& feature : enabledFeatures) {
                        std::cout << feature << " ";
                    }
                    std::cout << "\n";
                }

                std::cout << "Feature Configurations:\n";
                if (featureConfigs.empty()) {
                    std::cout << "None\n";
                } else {
                    std::cout << featureConfigs.dump(4) << std::endl;
                }
                break;
            }

            case 2: {  // Enable a feature
                std::string featureName;
                std::cout << "Enter feature name to enable: ";
                std::getline(std::cin, featureName);

                try {
                    // Check if configuration exists for this feature
                    if (!featureConfigs.contains(featureName)) {
                        std::cout << "Warning: No configuration found for feature '" << featureName 
                                  << "'. Adding with default settings.\n";
                        featureConfigs[featureName] = json::object();
                    }

                    enabledFeatures.insert(featureName);
                    std::cout << "Feature '" << featureName << "' has been enabled.\n";
                } catch (const std::exception& e) {
                    std::cerr << "Error enabling feature: " << e.what() << std::endl;
                }
                break;
            }

            case 3: {  // Disable a feature
                std::string featureName;
                std::cout << "Enter feature name to disable: ";
                std::getline(std::cin, featureName);

                auto it = enabledFeatures.find(featureName);
                if (it != enabledFeatures.end()) {
                    enabledFeatures.erase(it);
                    std::cout << "Feature '" << featureName << "' has been disabled.\n";
                } else {
                    std::cout << "Feature '" << featureName << "' is not currently enabled.\n";
                }
                break;
            }

            case 4: {  // Update feature parameters
                std::string featureName;
                std::cout << "Enter feature name to configure: ";
                std::getline(std::cin, featureName);

                if (!featureConfigs.contains(featureName)) {
                    std::cout << "Error: Feature '" << featureName << "' not found in configuration.\n";
                    break;
                }

                std::string paramName, paramValue;
                std::cout << "Enter parameter name: ";
                std::getline(std::cin, paramName);

                std::cout << "Enter parameter value: ";
                std::getline(std::cin, paramValue);

                try {
                    // Try to parse as number or boolean first
                    if (paramValue == "true") {
                        featureConfigs[featureName][paramName] = true;
                    } else if (paramValue == "false") {
                        featureConfigs[featureName][paramName] = false;
                    } else {
                        try {
                            // Try to parse as integer
                            int intValue = std::stoi(paramValue);
                            featureConfigs[featureName][paramName] = intValue;
                        } catch (...) {
                            try {
                                // Try to parse as double
                                double doubleValue = std::stod(paramValue);
                                featureConfigs[featureName][paramName] = doubleValue;
                            } catch (...) {
                                // Store as string if not a number or boolean
                                featureConfigs[featureName][paramName] = paramValue;
                            }
                        }
                    }

                    std::cout << "Parameter '" << paramName << "' updated for feature '" 
                              << featureName << "'.\n";
                } catch (const std::exception& e) {
                    std::cerr << "Error updating parameter: " << e.what() << std::endl;
                }
                break;
            }

            case 5: {  // Save configuration to file
                std::string filename;
                std::cout << "Enter filename to save configuration: ";
                std::getline(std::cin, filename);

                try {
                    // Create a json object containing both enabled features and configurations
                    json configToSave;
                    configToSave["enabledFeatures"] = enabledFeatures;
                    configToSave["featureConfigs"] = featureConfigs;

                    std::ofstream file(filename);
                    if (!file.is_open()) {
                        throw std::runtime_error("Could not open file for writing");
                    }

                    file << configToSave.dump(4);
                    file.close();

                    std::cout << "Configuration saved to '" << filename << "' successfully.\n";
                } catch (const std::exception& e) {
                    std::cerr << "Error saving configuration: " << e.what() << std::endl;
                }
                break;
            }

            case 6: {  // Load configuration from file
                std::string filename;
                std::cout << "Enter filename to load configuration: ";
                std::getline(std::cin, filename);

                try {
                    std::ifstream file(filename);
                    if (!file.is_open()) {
                        throw std::runtime_error("Could not open file for reading");
                    }

                    json loadedConfig;
                    file >> loadedConfig;
                    file.close();

                    // Validate the loaded JSON structure
                    if (!loadedConfig.contains("enabledFeatures") || !loadedConfig.contains("featureConfigs")) {
                        throw std::runtime_error("Invalid configuration file format");
                    }

                    // Update the current settings
                    enabledFeatures = loadedConfig["enabledFeatures"].get<std::set<std::string>>();
                    featureConfigs = loadedConfig["featureConfigs"];

                    std::cout << "Configuration loaded from '" << filename << "' successfully.\n";
                } catch (const std::exception& e) {
                    std::cerr << "Error loading configuration: " << e.what() << std::endl;
                }
                break;
            }

            case 7: {  // Reset to default settings
                char confirm;
                std::cout << "Are you sure you want to reset to default settings? (y/n): ";
                std::cin >> confirm;
                std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');

                if (confirm == 'y' || confirm == 'Y') {
                    enabledFeatures.clear();
                    featureConfigs.clear();

                    // Add your default feature configuration here
                    enabledFeatures.insert("defaultFeature");
                    featureConfigs["defaultFeature"]["param1"] = "default";
                    featureConfigs["defaultFeature"]["param2"] = 100;

                    std::cout << "Settings reset to default.\n";
                }
                break;
            }

            case 8:  // Exit
                exitMenu = true;
                std::cout << "Exiting feature configuration.\n";
                break;

            default:
                std::cout << "Invalid choice. Please select a valid option.\n";
                break;
        }
    }
}

public Float adjustBrightness(Float currentBrightness) {
    Scanner scanner = new Scanner(System.in);
    System.out.println("Current brightness: " + currentBrightness);
    System.out.println("Enter 'increase', 'decrease', or 'reset' to adjust brightness:");
    String input = scanner.nextLine().toLowerCase();

    Float newBrightness = currentBrightness;

    if (currentBrightness < 0.0 || currentBrightness > 1.0) {
        System.out.println("Error: Current brightness value is invalid. Must be between 0.0 and 1.0.");
        return currentBrightness;
    }

    switch (input) {
        case "increase":
            newBrightness = currentBrightness + 0.1f;
            if (newBrightness > 1.0) {
                newBrightness = 1.0f;
                System.out.println("Brightness already at maximum level (1.0).");
            } else {
                System.out.println("Brightness increased to: " + newBrightness);
            }
            break;
        case "decrease":
            newBrightness = currentBrightness - 0.1f;
            if (newBrightness < 0.0) {
                newBrightness = 0.0f;
                System.out.println("Brightness already at minimum level (0.0).");
            } else {
                System.out.println("Brightness decreased to: " + newBrightness);
            }
            break;
        case "reset":
            newBrightness = 0.5f;
            System.out.println("Brightness reset to default level (0.5).");
            break;
        default:
            System.out.println("Error: Invalid input. Please enter 'increase', 'decrease', or 'reset'.");
            break;
    }

    return newBrightness;
}

