std::vector<int> traverseGraph(const std::vector<std::vector<int>>& adjMatrix, int startNode) {
    // Validate input parameters
    if (adjMatrix.empty()) {
        throw std::invalid_argument("Empty adjacency matrix");
    }

    int n = adjMatrix.size();
    for (const auto& row : adjMatrix) {
        if (row.size() != n) {
            throw std::invalid_argument("Adjacency matrix is not square");
        }
    }

    if (startNode < 0 || startNode >= n) {
        throw std::invalid_argument("Invalid start node index");
    }

    // BFS algorithm
    std::vector<bool> visited(n, false);
    std::vector<int> result;
    std::queue<int> q;

    visited[startNode] = true;
    q.push(startNode);

    while (!q.empty()) {
        int current = q.front();
        q.pop();
        result.push_back(current);

        for (int i = 0; i < n; i++) {
            if (adjMatrix[current][i] && !visited[i]) {
                visited[i] = true;
                q.push(i);
            }
        }
    }

    return result;
}

/// Calculates the displacement of a moving object.
///
/// # Parameters
/// * `initial_velocity` - The initial velocity of the object in meters per second
/// * `time` - The elapsed time in seconds
///
/// # Returns
/// * `Result<f64, String>` - The displacement in meters if successful, or an error message if time is negative
pub fn calculate_displacement(initial_velocity: f64, time: f64) -> Result<f64, String> {
    if time < 0.0 {
        return Err("Invalid input: time cannot be negative".to_string());
    }

    let displacement = initial_velocity * time + 0.5 * 9.8 * time.powi(2);
    Ok(displacement)
}

