std::map<std::string, double> processData(const std::map<std::string, double>& data) {
    std::map<std::string, double> results;

    // Handle empty input case
    if (data.empty()) {
        return results;
    }

    // Initialize variables
    double min = std::numeric_limits<double>::max();
    double max = std::numeric_limits<double>::lowest();
    double sum = 0.0;
    int validCount = 0;

    // Process each key-value pair
    for (const auto& pair : data) {
        // Input validation for non-negative values
        if (pair.second < 0.0) {
            continue; // Skip negative values
        }

        // Update statistics
        min = std::min(min, pair.second);
        max = std::max(max, pair.second);
        sum += pair.second;
        validCount++;
    }

    // Calculate and store results
    if (validCount > 0) {
        results["min"] = min;
        results["max"] = max;
        results["sum"] = sum;
        results["average"] = sum / validCount;
    }

    return results;
}

public static int findClosestValueInBst(Tree tree, int target) {
    Tree currentNode = tree;
    int closest = tree.value;

    while (currentNode != null) {
        if (Math.abs(target - closest) > Math.abs(target - currentNode.value)) {
            closest = currentNode.value;
        }

        if (target < currentNode.value) {
            currentNode = currentNode.left;
        } else if (target > currentNode.value) {
            currentNode = currentNode.right;
        } else {
            break;
        }
    }

    return closest;
}

