def manage_queue_operations(queue: deque, max_size: int):
    """
    Manages operations on a queue with a maximum size limit.

    Args:
        queue: A deque object to perform operations on
        max_size: Maximum allowed size of the queue

    Returns:
        Dictionary with queue management functions and properties
    """
    def add_element(element):
        if len(queue) >= max_size:
            raise ValueError("Cannot add element: maximum queue size reached")
        queue.append(element)
        return True

    def remove_element():
        if not queue:
            raise ValueError("Cannot remove element: queue is empty")
        return queue.popleft()

    return {
        "add": add_element,
        "remove": remove_element,
        "current_queue": queue,
        "current_size": len(queue),
        "max_size": max_size
    }

