std::vector<int> findShortestPath(const std::vector<std::vector<std::pair<int, int>>>& graph, 
                                 int startNode, 
                                 int endNode) {
    // Check if nodes are valid
    if (startNode < 0 || startNode >= graph.size() || endNode < 0 || endNode >= graph.size()) {
        throw std::invalid_argument("Starting or ending node does not exist in the graph");
    }

    // Priority queue for Dijkstra's algorithm (distance, node)
    std::priority_queue<std::pair<int, int>, 
                        std::vector<std::pair<int, int>>, 
                        std::greater<std::pair<int, int>>> pq;

    // Distance vector and predecessor vector
    std::vector<int> distance(graph.size(), std::numeric_limits<int>::max());
    std::vector<int> predecessor(graph.size(), -1);

    // Distance to start node is 0
    distance[startNode] = 0;
    pq.push({0, startNode});

    // Dijkstra's algorithm
    while (!pq.empty()) {
        int currentDist = pq.top().first;
        int currentNode = pq.top().second;
        pq.pop();

        // If we reached the destination, we can stop
        if (currentNode == endNode) {
            break;
        }

        // If this is not the shortest distance, skip
        if (currentDist > distance[currentNode]) {
            continue;
        }

        // Check all neighbors
        for (const auto& neighbor : graph[currentNode]) {
            int nextNode = neighbor.first;
            int weight = neighbor.second;

            if (distance[currentNode] + weight < distance[nextNode]) {
                distance[nextNode] = distance[currentNode] + weight;
                predecessor[nextNode] = currentNode;
                pq.push({distance[nextNode], nextNode});
            }
        }
    }

    // If no path exists
    if (distance[endNode] == std::numeric_limits<int>::max()) {
        return {};  // Return empty path
    }

    // Reconstruct the path
    std::vector<int> path;
    for (int at = endNode; at != -1; at = predecessor[at]) {
        path.push_back(at);
    }

    // Reverse to get path from start to end
    std::reverse(path.begin(), path.end());

    return path;
}
