float calculateMortgagePayment(float principal, float annualInterestRate, int loanTermYears) {
    // Error handling for invalid inputs
    if (principal <= 0 || annualInterestRate <= 0 || loanTermYears <= 0) {
        return -1.0f; // Return negative value to indicate error
    }

    // Convert annual interest rate to monthly and decimal form
    float monthlyInterestRate = annualInterestRate / 12.0f / 100.0f;

    // Calculate number of payments
    int numberOfPayments = loanTermYears * 12;

    // Calculate monthly payment using the fixed-rate mortgage formula
    float monthlyPayment = principal * 
                          (monthlyInterestRate * pow(1 + monthlyInterestRate, numberOfPayments)) / 
                          (pow(1 + monthlyInterestRate, numberOfPayments) - 1);

    return monthlyPayment;
}

