            if (matrix == null || matrix.length == 0) {
                System.err.println("Error: Connectivity matrix cannot be null or empty");
                return;
            }

            // Check if tuple position is within matrix boundaries
            if (row < 0 || row >= matrix.length || 
                column < 0 || column >= matrix[0].length) {
                System.err.println("Error: Junction position [" + row + ", " + column + 
                                  "] is outside the matrix boundaries");
                return;
            }

            System.out.println("Analyzing connections from junction at position [" + row + ", " + column + "]:");

            // Define direction vectors (North, East, South, West)
            int[] dx = {-1, 0, 1, 0};
            int[] dy = {0, 1, 0, -1};
            String[] directions = {"North", "East", "South", "West"};

            // Check connections in all four directions
            for (int i = 0; i < 4; i++) {
                int newRow = row + dx[i];
                int newCol = column + dy[i];

                // Check if the new position is within boundaries and connected
                if (newRow >= 0 && newRow < matrix.length && 
                    newCol >= 0 && newCol < matrix[0].length && 
                    matrix[newRow][newCol] == 1) {
                    System.out.println("Connected to junction at [" + newRow + ", " + newCol + 
                                      "] (" + directions[i] + ")");
                }
            }
        } catch (Exception e) {
            System.err.println("Error analyzing road network: " + e.getMessage());
        }
    }
